INSERT INTO rag_task_executions 
  (trace_id, task_id, intent_id, status, rag_called, attempt, query, confidence)
VALUES {{ $json.tasks_to_insert.map(t => 
  `('${t.trace_id}', ${t.task_id}, '${t.intent_id}', '${t.status}', '${t.rag_called}', ${t.attempt}, '${t.query}', ${t.confidence})`
).join(', ') }}
ON CONFLICT (trace_id, task_id) DO UPDATE 
SET status = 'pending', updated_at = NOW();

